(window.webpackJsonp=window.webpackJsonp||[]).push([[1021],{991:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * Initialize your data structure here.\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> MyQueue = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\"></span>) </span>{\\n  <span class=\\"hljs-keyword\\">this</span>.stack1=[]\\n  <span class=\\"hljs-keyword\\">this</span>.stack2=[]\\n};\\n\\n<span class=\\"hljs-comment\\">/**\\n * Push element x to the back of queue. \\n * @param {number} x\\n * @return {void}\\n */</span>\\nMyQueue.prototype.push = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">x</span>) </span>{\\n  <span class=\\"hljs-keyword\\">this</span>.stack1.push(x)\\n};\\n\\n<span class=\\"hljs-comment\\">/**\\n * Removes the element from in front of queue and returns that element.\\n * @return {number}\\n */</span>\\nMyQueue.prototype.pop = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\"></span>) </span>{\\n  <span class=\\"hljs-keyword\\">this</span>.peek()\\n  <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-keyword\\">this</span>.stack2.pop()\\n};\\n\\n<span class=\\"hljs-comment\\">/**\\n * Get the front element.\\n * @return {number}\\n */</span>\\nMyQueue.prototype.peek = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\"></span>) </span>{\\n  <span class=\\"hljs-keyword\\">if</span>(<span class=\\"hljs-keyword\\">this</span>.stack2.length===<span class=\\"hljs-number\\">0</span>){\\n    <span class=\\"hljs-keyword\\">while</span>(<span class=\\"hljs-keyword\\">this</span>.stack1.length&gt;<span class=\\"hljs-number\\">0</span>){\\n      <span class=\\"hljs-keyword\\">this</span>.stack2.push(<span class=\\"hljs-keyword\\">this</span>.stack1.pop())\\n    }    \\n  }\\n  <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-keyword\\">this</span>.stack2[<span class=\\"hljs-keyword\\">this</span>.stack2.length<span class=\\"hljs-number\\">-1</span>]\\n};\\n\\n<span class=\\"hljs-comment\\">/**\\n * Returns whether the queue is empty.\\n * @return {boolean}\\n */</span>\\nMyQueue.prototype.empty = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\"></span>) </span>{\\n  <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-keyword\\">this</span>.stack1.length===<span class=\\"hljs-number\\">0</span> &amp;&amp; <span class=\\"hljs-keyword\\">this</span>.stack2.length===<span class=\\"hljs-number\\">0</span> \\n};\\n\\n<span class=\\"hljs-comment\\">/** \\n * Your MyQueue object will be instantiated and called as such:\\n * var obj = new MyQueue()\\n * obj.push(x)\\n * var param_2 = obj.pop()\\n * var param_3 = obj.peek()\\n * var param_4 = obj.empty()\\n */</span>\\n</code></pre>\\n"],"titleSlug":"implement-queue-using-stacks","hasThinking":false,"content":"<p>\u8bf7\u4f60\u4ec5\u4f7f\u7528\u4e24\u4e2a\u6808\u5b9e\u73b0\u5148\u5165\u5148\u51fa\u961f\u5217\u3002\u961f\u5217\u5e94\u5f53\u652f\u6301\u4e00\u822c\u961f\u5217\u652f\u6301\u7684\u6240\u6709\u64cd\u4f5c\uff08<code>push</code>\u3001<code>pop</code>\u3001<code>peek</code>\u3001<code>empty</code>\uff09\uff1a</p>\\n\\n<p>\u5b9e\u73b0 <code>MyQueue</code> \u7c7b\uff1a</p>\\n\\n<ul>\\n\\t<li><code>void push(int x)</code> \u5c06\u5143\u7d20 x \u63a8\u5230\u961f\u5217\u7684\u672b\u5c3e</li>\\n\\t<li><code>int pop()</code> \u4ece\u961f\u5217\u7684\u5f00\u5934\u79fb\u9664\u5e76\u8fd4\u56de\u5143\u7d20</li>\\n\\t<li><code>int peek()</code> \u8fd4\u56de\u961f\u5217\u5f00\u5934\u7684\u5143\u7d20</li>\\n\\t<li><code>boolean empty()</code> \u5982\u679c\u961f\u5217\u4e3a\u7a7a\uff0c\u8fd4\u56de <code>true</code> \uff1b\u5426\u5219\uff0c\u8fd4\u56de <code>false</code></li>\\n</ul>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u8bf4\u660e\uff1a</strong></p>\\n\\n<ul>\\n\\t<li>\u4f60\u53ea\u80fd\u4f7f\u7528\u6807\u51c6\u7684\u6808\u64cd\u4f5c \u2014\u2014 \u4e5f\u5c31\u662f\u53ea\u6709\xa0<code>push to top</code>,\xa0<code>peek/pop from top</code>,\xa0<code>size</code>, \u548c\xa0<code>is empty</code>\xa0\u64cd\u4f5c\u662f\u5408\u6cd5\u7684\u3002</li>\\n\\t<li>\u4f60\u6240\u4f7f\u7528\u7684\u8bed\u8a00\u4e5f\u8bb8\u4e0d\u652f\u6301\u6808\u3002\u4f60\u53ef\u4ee5\u4f7f\u7528 list \u6216\u8005 deque\uff08\u53cc\u7aef\u961f\u5217\uff09\u6765\u6a21\u62df\u4e00\u4e2a\u6808\uff0c\u53ea\u8981\u662f\u6807\u51c6\u7684\u6808\u64cd\u4f5c\u5373\u53ef\u3002</li>\\n</ul>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u8fdb\u9636\uff1a</strong></p>\\n\\n<ul>\\n\\t<li>\u4f60\u80fd\u5426\u5b9e\u73b0\u6bcf\u4e2a\u64cd\u4f5c\u5747\u644a\u65f6\u95f4\u590d\u6742\u5ea6\u4e3a <code>O(1)</code> \u7684\u961f\u5217\uff1f\u6362\u53e5\u8bdd\u8bf4\uff0c\u6267\u884c <code>n</code> \u4e2a\u64cd\u4f5c\u7684\u603b\u65f6\u95f4\u590d\u6742\u5ea6\u4e3a <code>O(n)</code> \uff0c\u5373\u4f7f\u5176\u4e2d\u4e00\u4e2a\u64cd\u4f5c\u53ef\u80fd\u82b1\u8d39\u8f83\u957f\u65f6\u95f4\u3002</li>\\n</ul>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>\\n[\\"MyQueue\\", \\"push\\", \\"push\\", \\"peek\\", \\"pop\\", \\"empty\\"]\\n[[], [1], [2], [], [], []]\\n<strong>\u8f93\u51fa\uff1a</strong>\\n[null, null, null, 1, 1, false]\\n\\n<strong>\u89e3\u91ca\uff1a</strong>\\nMyQueue myQueue = new MyQueue();\\nmyQueue.push(1); // queue is: [1]\\nmyQueue.push(2); // queue is: [1, 2] (leftmost is front of the queue)\\nmyQueue.peek(); // return 1\\nmyQueue.pop(); // return 1, queue is [2]\\nmyQueue.empty(); // return false\\n</pre>\\n\\n<ul>\\n</ul>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= x <= 9</code></li>\\n\\t<li>\u6700\u591a\u8c03\u7528 <code>100</code> \u6b21 <code>push</code>\u3001<code>pop</code>\u3001<code>peek</code> \u548c <code>empty</code></li>\\n\\t<li>\u5047\u8bbe\u6240\u6709\u64cd\u4f5c\u90fd\u662f\u6709\u6548\u7684 \uff08\u4f8b\u5982\uff0c\u4e00\u4e2a\u7a7a\u7684\u961f\u5217\u4e0d\u4f1a\u8c03\u7528 <code>pop</code> \u6216\u8005 <code>peek</code> \u64cd\u4f5c\uff09</li>\\n</ul>\\n","title":"232. \u7528\u6808\u5b9e\u73b0\u961f\u5217","relatedTags":["\u6808","\u8bbe\u8ba1"],"difficult":"Easy","lang":["javascript"],"uniqueID":"232"}')}}]);